        val timestamp = dateFormat.format(Date())
        Timber.i("AUTH_SUCCESS: User logged in successfully | UserID: $maskedUserId | Time: $timestamp")
    }

    fun logFailedLogin(username: String, reason: String) {
        val maskedUsername = maskUsername(username)
        val timestamp = dateFormat.format(Date())
        Timber.w("AUTH_FAILED: Login attempt failed | Username: $maskedUsername | Reason: $reason | Time: $timestamp")
    }

    fun logLogout(userId: String) {
        val maskedUserId = maskUserId(userId)
        val timestamp = dateFormat.format(Date())
        Timber.i("AUTH_LOGOUT: User logged out | UserID: $maskedUserId | Time: $timestamp")
    }

    fun logPasswordReset(email: String) {
        val maskedEmail = maskEmail(email)
        val timestamp = dateFormat.format(Date())
        Timber.i("AUTH_PASSWORD_RESET: Password reset requested | Email: $maskedEmail | Time: $timestamp")
    }

    fun logSessionExpired(userId: String) {
        val maskedUserId = maskUserId(userId)
        val timestamp = dateFormat.format(Date())
        Timber.i("AUTH_SESSION_EXPIRED: Session expired | UserID: $maskedUserId | Time: $timestamp")
    }

    private fun maskUserId(userId: String): String {
        return if (userId.length > 4) {
            userId.take(4) + "****"
        } else {
            "****"
        }
    }

    private fun maskUsername(username: String): String {
        return if (username.contains("@")) {
            maskEmail(username)
        } else {
            if (username.length > 3) {
                username.take(3) + "***"
            } else {
                "***"
            }
        }
    }

    private fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***.***"
        val username = parts[0]
        val domain = parts[1]
        val maskedUsername = if (username.length > 2) {
            username.take(2) + "***"
        } else {
            "***"
        }
        return "$maskedUsername@$domain"
    }
