class DatabaseLogger {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)

    fun logQuery(query: String, parameters: List<Any?>? = null, executionTimeMs: Long? = null) {
        val sanitizedQuery = sanitizeQuery(query)
        val sanitizedParams = parameters?.let { sanitizeParameters(it) } ?: "none"
        val timestamp = dateFormat.format(Date())
        val execTime = executionTimeMs?.let { " | ExecutionTime: ${it}ms" } ?: ""
        
        Timber.d("DB_QUERY: $sanitizedQuery | Params: $sanitizedParams | Time: $timestamp$execTime")
    }

    fun logInsert(table: String, rowCount: Int) {
        val timestamp = dateFormat.format(Date())
        Timber.d("DB_INSERT: Table: $table | Rows: $rowCount | Time: $timestamp")
    }

    fun logUpdate(table: String, rowsAffected: Int) {
        val timestamp = dateFormat.format(Date())
        Timber.d("DB_UPDATE: Table: $table | RowsAffected: $rowsAffected | Time: $timestamp")
    }

    fun logDelete(table: String, rowsAffected: Int) {
        val timestamp = dateFormat.format(Date())
        Timber.d("DB_DELETE: Table: $table | RowsAffected: $rowsAffected | Time: $timestamp")
    }

    fun logError(operation: String, error: Throwable) {
        val timestamp = dateFormat.format(Date())
        Timber.e(error, "DB_ERROR: Operation: $operation | Time: $timestamp")
    }

    private fun sanitizeQuery(query: String): String {
        return query
            .replace(Regex("'[^']*password[^']*'", RegexOption.IGNORE_CASE), "'***'")
            .replace(Regex("'[^']*token[^']*'", RegexOption.IGNORE_CASE), "'***'")
            .replace(Regex("'[^']*secret[^']*'", RegexOption.IGNORE_CASE), "'***'")
    }

    private fun sanitizeParameters(params: List<Any?>): String {
        return params.joinToString(", ") { param ->
            when {
                param == null -> "null"
                param is String && isSensitiveData(param) -> "***"
                param is String -> "\"${param.take(50)}${if (param.length > 50) "..." else ""}\""
                else -> param.toString()
            }
        }
    }

    private fun isSensitiveData(value: String): Boolean {
        val lowerValue = value.lowercase()
        return lowerValue.contains("password") ||
               lowerValue.contains("token") ||
               lowerValue.contains("secret") ||
               lowerValue.contains("api_key") ||
               lowerValue.contains("bearer")
    }
}

class ApiLogger {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)

    fun logRequest(
        method: String,
        url: String,
        headers: Map<String, String>? = null,
        body: String? = null
    ) {
        val sanitizedUrl = sanitizeUrl(url)
        val sanitizedHeaders = headers?.let { sanitizeHeaders(it) } ?: "none"
        val sanitizedBody = body?.let { sanitizeBody(it) } ?: "none"
        val timestamp = dateFormat.format(Date())
        
        Timber.d("API_REQUEST: $method $sanitizedUrl | Headers: $sanitizedHeaders | Body: $sanitizedBody | Time: $timestamp")
    }

    fun logResponse(
        method: String,
        url: String,
        statusCode: Int,
        responseBody: String? = null,
        durationMs: Long? = null
    ) {
        val sanitizedUrl = sanitizeUrl(url)
        val sanitizedBody = responseBody?.let { sanitizeBody(it) } ?: "none"
        val timestamp = dateFormat.format(Date())
        val duration = durationMs?.let { " | Duration: ${it}ms" } ?: ""
        
        Timber.d("API_RESPONSE: $method $sanitizedUrl | Status: $statusCode | Body: $sanitizedBody | Time: $timestamp$duration")
    }

    fun logError(method: String, url: String, error: Throwable) {
        val sanitizedUrl = sanitizeUrl(url)
        val timestamp = dateFormat.format(Date())
        Timber.e(error, "API_ERROR: $method $sanitizedUrl | Time: $timestamp")
    }

    private fun sanitizeUrl(url: String): String {
        return url
            .replace(Regex("([?&])(token|api_key|key|secret)=[^&]*", RegexOption.IGNORE_CASE), "$1$2=***")
            .replace(Regex("(access_token|refresh_token)=[^&]*", RegexOption.IGNORE_CASE), "$1=***")
    }

    private fun sanitizeHeaders(headers: Map<String, String>): String {
        val sanitized = headers.mapValues { (key, value) ->
            when {
                key.equals("Authorization", ignoreCase = true) -> "***"
                key.equals("Cookie", ignoreCase = true) -> "***"
                key.contains("token", ignoreCase = true) -> "***"
                key.contains("key", ignoreCase = true) -> "***"
                key.contains("secret", ignoreCase = true) -> "***"
                else -> value
            }
        }
        return sanitized.entries.joinToString(", ") { "${it.key}: ${it.value}" }
    }

    private fun sanitizeBody(body: String): String {
        if (body.length > 1000) {
            return sanitizeBodyContent(body.take(1000)) + "... [truncated]"
        }
        return sanitizeBodyContent(body)
    }

    private fun sanitizeBodyContent(body: String): String {
        return body
            .replace(Regex("\"password\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"password\":\"***\"")
            .replace(Regex("\"token\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"token\":\"***\"")
            .replace(Regex("\"api_key\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"api_key\":\"***\"")
            .replace(Regex("\"secret\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"secret\":\"***\"")
            .replace(Regex("\"authorization\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"authorization\":\"***\"")
            .replace(Regex("\"credit_card\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"credit_card\":\"***\"")
            .replace(Regex("\"ssn\"\\s*:\\s*\"[^\"]*\"", RegexOption.IGNORE_CASE), "\"ssn\":\"***\"")
    }
}

class ExceptionLogger {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)

    fun logException(throwable: Throwable, context: String? = null) {
        val timestamp = dateFormat.format(Date())
        val contextInfo = context?.let { " | Context: $it" } ?: ""
        Timber.e(throwable, "EXCEPTION: ${throwable.javaClass.simpleName}$contextInfo | Time: $timestamp")
    }

    fun logCrash(throwable: Throwable, additionalInfo: Map<String, String>? = null) {
        val timestamp = dateFormat.format(Date())
        val info = additionalInfo?.let { 
            " | Info: ${it.entries.joinToString(", ") { "${it.key}=${it.value}" }}" 
        } ?: ""
        Timber.e(throwable, "CRASH: ${throwable.javaClass.simpleName}$info | Time: $timestamp")
    }

    fun logHandledException(throwable: Throwable, handledBy: String) {
        val timestamp = dateFormat.format(Date())
        Timber.w(throwable, "HANDLED_EXCEPTION: ${throwable.javaClass.simpleName} | HandledBy: $handledBy | Time: $timestamp")
    }
}

